Remediation_Commands:
1. dmesg | grep -i 'i/o error\|sd\|multipath' | tail -30
2. multipath -ll
3. asmcmd lsdsk
4. asmcmd lsof
5. sqlplus / as sysdba
6. SQL> SELECT GROUP_NUMBER, NAME, STATE FROM V$ASM_DISKGROUP;
7. SQL> SELECT DISK_NUMBER, NAME, PATH, MODE_STATUS, MOUNT_STATUS FROM V$ASM_DISK ORDER BY GROUP_NUMBER;
8. SQL> EXIT;

1. asmcmd lsdg
2. asmcmd lsdsk --discovery
3. sqlplus / as sysdba
4. SQL> SELECT GROUP_NUMBER, NAME, STATE, TYPE FROM V$ASM_DISKGROUP;
5. SQL> ALTER DISKGROUP <DGNAME> MOUNT;
6. SQL> EXIT;
7. multipath -ll
8. systemctl status multipathd

1. df -h /arch
2. du -sh /arch/* | sort -rh | head -20
3. rman target /
4. RMAN> DELETE ARCHIVELOG ALL COMPLETED BEFORE 'SYSDATE-1';
5. RMAN> EXIT;
6. sqlplus / as sysdba
7. SQL> SHOW PARAMETER db_recovery_file_dest_size;
8. SQL> ALTER SYSTEM SET db_recovery_file_dest_size=50G SCOPE=BOTH;
9. SQL> SELECT * FROM V$RECOVERY_FILE_DEST;
10. SQL> ALTER SYSTEM ARCHIVE LOG ALL;
11. SQL> EXIT;

1. sqlplus / as sysdba
2. SQL> SELECT * FROM V$RECOVERY_FILE_DEST;
3. SQL> SHOW PARAMETER db_recovery_file_dest_size;
4. SQL> ALTER SYSTEM SET db_recovery_file_dest_size=100G SCOPE=BOTH;
5. rman target /
6. RMAN> CROSSCHECK ARCHIVELOG ALL;
7. RMAN> DELETE EXPIRED ARCHIVELOG ALL;
8. RMAN> EXIT;

1. sqlplus / as sysdba
2. SQL> SELECT STATUS, SEQUENCE#, NAME FROM V$ARCHIVED_LOG ORDER BY SEQUENCE# DESC FETCH FIRST 10 ROWS ONLY;
3. SQL> SELECT * FROM V$ARCHIVE_DEST_STATUS WHERE STATUS != 'INACTIVE';
4. SQL> ALTER SYSTEM SWITCH LOGFILE;
5. SQL> ALTER SYSTEM ARCHIVE LOG ALL;
6. SQL> SELECT GROUP#, STATUS FROM V$LOG;
7. SQL> EXIT;

1. tail -500 $ORACLE_BASE/diag/rdbms/*/*/trace/alert_*.log | grep -B10 'ORA-00603'
2. ls -lt $ORACLE_BASE/diag/rdbms/*/*/trace/*.trc | head -5
3. adrci
4. ADRCI> SHOW INCIDENT;
5. ADRCI> SHOW PROBLEM;
6. ADRCI> EXIT;
7. sqlplus / as sysdba
8. SQL> SELECT INST_ID, STATUS, DATABASE_STATUS FROM GV$INSTANCE;
9. SQL> SELECT COUNT(*) FROM V$SESSION WHERE STATUS='ACTIVE';
10. SQL> EXIT;

1. grep -i hugepage /proc/meminfo
2. free -g
3. ipcs -m | head -20
4. sqlplus / as sysdba
5. SQL> SHOW PARAMETER sga_target;
6. SQL> SHOW PARAMETER pga_aggregate_target;
7. SQL> SELECT POOL, NAME, BYTES FROM V$SGASTAT WHERE NAME='free memory' ORDER BY POOL;
8. SQL> ALTER SYSTEM FLUSH SHARED_POOL;
9. SQL> ALTER SYSTEM SET MEMORY_TARGET=0 SCOPE=SPFILE;
10. SQL> EXIT;

1. ping -c 4 <db_host>
2. traceroute <db_host>
3. netstat -an | grep 1521
4. ss -antp | grep 1521
5. lsnrctl status
6. lsnrctl reload
7. sqlplus / as sysdba
8. SQL> SELECT SID, USERNAME, STATUS, MACHINE, LOGON_TIME FROM V$SESSION WHERE STATUS='KILLED';
9. SQL> SELECT EVENT, COUNT(*) FROM V$SESSION_WAIT GROUP BY EVENT ORDER BY COUNT(*) DESC FETCH FIRST 10 ROWS ONLY;
10. SQL> SHOW PARAMETER sqlnet;
11. SQL> EXIT;
12. tail -200 $ORACLE_BASE/diag/rdbms/*/*/trace/alert_*.log | grep -A5 'ORA-03113'

1. sqlplus / as sysdba
2. SQL> SELECT GROUP#, MEMBER FROM V$LOGFILE;
3. SQL> SELECT GROUP#, SEQUENCE#, STATUS, ARCHIVED FROM V$LOG;
4. SQL> ALTER DATABASE CLEAR LOGFILE GROUP <GROUP_NUMBER>;
5. SQL> ALTER DATABASE CLEAR UNARCHIVED LOGFILE GROUP <GROUP_NUMBER>;
6. SQL> RECOVER DATABASE UNTIL CANCEL;
7. SQL> ALTER DATABASE OPEN RESETLOGS;
8. SQL> EXIT;

1. tail -200 $ORACLE_BASE/diag/rdbms/*/*/trace/alert_*.log | grep -B5 'ORA-00470'
2. ls -lt $ORACLE_BASE/diag/rdbms/*/*/trace/orcl_lgwr_*.trc | head -3
3. sqlplus / as sysdba
4. SQL> SELECT GROUP#, STATUS, BYTES FROM V$LOG;
5. SQL> SELECT GROUP#, MEMBER FROM V$LOGFILE;
6. SQL> SELECT * FROM V$LOG WHERE STATUS='CURRENT';
7. SQL> EXIT;
8. df -h /redolog
9. iostat -xz 1 5

1. sqlplus / as sysdba
2. SQL> SELECT FILE#, BLOCK#, BLOCKS, CORRUPTION_TYPE FROM V$DATABASE_BLOCK_CORRUPTION;
3. SQL> SELECT NAME FROM V$DATAFILE WHERE FILE# = <FILE_NUMBER>;
4. SQL> EXIT;
5. rman target /
6. RMAN> BLOCKRECOVER DATAFILE <FILE_NUMBER> BLOCK <BLOCK_NUMBER>;
7. RMAN> VALIDATE DATABASE;
8. RMAN> EXIT;

1. adrci
2. ADRCI> SHOW INCIDENT;
3. ADRCI> SHOW PROBLEM;
4. ADRCI> IPS PACK INCIDENT <INCIDENT_ID> IN '/tmp';
5. ADRCI> EXIT;
6. tail -200 $ORACLE_BASE/diag/rdbms/*/*/trace/alert_*.log | grep -B10 'ORA-07445'
7. sqlplus / as sysdba
8. SQL> SELECT VALUE FROM V$DIAG_INFO WHERE NAME='Default Trace File';
9. SQL> SHOW PARAMETER optimizer;
10. SQL> EXIT;
11. opatch lsinventory | grep -i 'Patch'
